$(document).ready(function(){$(window).scroll(function(){$(window).scrollTop()>=5?$(".header").addClass("header--animated"):$(".header").removeClass("header--animated")}),$("[data-click=scroll-to-target]").on("click",function(a){a.preventDefault(),a.stopPropagation();var e=$(this).attr("href");$("html, body").animate({scrollTop:$(e).offset().top-78},500)})});